SMED = {"AA": 0.198, "SS": 0.437, "3Di": 0.238}

# ---------- FIGURE 1: lengths ----------
plt.figure(figsize=(9, 5))
for k in ["synthetic", "AA", "SS", "3Di"]:
    plt.plot(LEN_X, _sm(LEN[k]), color=COL[k], lw=2.2, label=k)
    plt.fill_between(LEN_X, _sm(LEN[k]), color=COL[k], alpha=0.10)
plt.xlabel("sequence length"); plt.ylabel("density")
plt.title("Sequence-length distribution — four sets")
plt.legend(); plt.tight_layout(); plt.savefig("four_sets_lengths.png", dpi=150, bbox_inches="tight"); plt.show()

# ---------- FIGURE 2: letter frequency ----------
x = np.arange(20)
plt.figure(figsize=(9, 5))
for k in ["synthetic", "AA", "SS", "3Di"]:
    plt.plot(x, LFREQ[k], color=COL[k], lw=2.0, marker="o", ms=4, label=k)
plt.axhline(1/20, ls=":", lw=1, color="0.5")
plt.text(19.2, 1/20, "uniform (1/20)", fontsize=8, color="0.5", va="center")
plt.xticks(x, LETTERS); plt.xlabel("amino-acid letter"); plt.ylabel("frequency")
plt.title("Letter-frequency distribution — four sets (SS uses only H, L, S)")
plt.legend(); plt.tight_layout(); plt.savefig("four_sets_letterfreq.png", dpi=150, bbox_inches="tight"); plt.show()

# ---------- FIGURE 3: score (normLev) distribution ----------
plt.figure(figsize=(9, 5))
for k in ["AA", "SS", "3Di"]:
    plt.plot(SCORE_X, _sm(SCORE[k]), color=COL[k], lw=2.2, label=f"{k}  (median {SMED[k]:.2f})")
    plt.fill_between(SCORE_X, _sm(SCORE[k]), color=COL[k], alpha=0.12)
plt.axvline(0.70, ls="--", lw=1, color="0.4")
plt.text(0.71, plt.ylim()[1]*0.88, "high-sim bar (0.70)", fontsize=8, color="0.4")
plt.xlabel("normalized Levenshtein similarity (true score)"); plt.ylabel("density")
plt.title("Distribution of true edit-similarity scores per alphabet (CATH_s20 pool)")
plt.legend(title="alphabet"); plt.xlim(0, 1); plt.tight_layout()
plt.savefig("four_sets_score_distribution.png", dpi=150, bbox_inches="tight"); plt.show()
